// ===================== fixed machinery (stable) =====================

// Accept args as an object OR a JSON string (some invocation paths stringify it).
let a = args || {};
if (typeof a === 'string') {
  try { a = JSON.parse(a); } catch (e) { a = { feature: a }; }
}
const feature = String((typeof a === 'string' ? a : a.feature) || '').trim();
if (!feature) throw new Error(`${VERILOOP.repoName}-dev-loop: pass args.feature (the feature to build).`);
// dryRun: plan -> implement -> gate -> fix, but STOP before docs-sync/push.
const dryRun = typeof a === 'object' && a.dryRun === true;
// waive: array of substrings; a blocker matching one is downgraded to WAIVED
// (human-authored waiver — an agent may never waive its own finding).
const waivers = (typeof a === 'object' && Array.isArray(a.waive)) ? a.waive.map(String) : [];
// spec: the OWNER'S answers from the /dev-loop spec interview. The interview
// cannot happen here — this workflow's agents are background subagents with no
// channel to ask the user — so it runs in the `/dev-loop` command (main loop)
// and its outcome arrives as text. Absent = an unambiguous feature, or an
// autonomous run; the loop behaves exactly as before.
const spec = (typeof a === 'object' && typeof a.spec === 'string') ? a.spec.trim() : '';
const MAX_FIX = 3;

// <<< veriloop:route:start >>>
// Cost/quality routing. Each phase GROUP (plan / implement / review / checks /
// fix / land) resolves its model + reasoning effort: a per-run arg wins, then
// the repo's configured override, then the posture preset. Nothing set ⇒ omit
// the option entirely, so the agent inherits the session's model.
//
// INVARIANT: routing changes only HOW WELL each judgment layer thinks — never
// WHICH jobs run. No posture can drop a gate check, a review lens, or the
// baseline probe. The exit-code gate is the ground truth and is not a cost dial.
function routeFor(group, budget, argModels, argEffort, argPosture) {
  const b = budget || {};
  const posture = argPosture || b.posture || 'balanced';
  const preset = ((b.presets || {})[posture] || {})[group] || {};
  const model = (argModels || {})[group] || (b.models || {})[group] || preset.model || null;
  const effort = (argEffort || {})[group] || (b.effort || {})[group] || preset.effort || null;
  const opts = {};
  if (model) opts.model = model;
  if (effort) opts.effort = effort;
  return opts;
}
// <<< veriloop:route:end >>>
const argsObj = (typeof a === 'object' && a) || {};
const route = (group) => routeFor(group, VERILOOP.budget, argsObj.models, argsObj.effort, argsObj.posture);

// Every agent that runs shell resolves the repo root itself — keeps this file
// free of any machine-specific absolute path.
const RESOLVE =
  'Resolve the repo root once: REPO="${CLAUDE_PROJECT_DIR:-$(git rev-parse --show-toplevel)}" ' +
  '(use that; NEVER a hardcoded absolute path). All repo-relative paths below are under $REPO.';

const CONSTITUTION = VERILOOP.constitution; // repo-relative path

// ---------------- schemas ----------------
const sev = { type: 'string', enum: ['BLOCKER', 'SHOULD-FIX', 'NIT'] };
const finding = {
  type: 'object', additionalProperties: false,
  required: ['severity', 'location', 'issue', 'fix'],
  properties: { severity: sev, location: { type: 'string' }, issue: { type: 'string' }, fix: { type: 'string' } },
};
const PLAN_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['plan', 'tier', 'touchedAreas', 'constitutionOk', 'constitutionViolations', 'planConcerns'],
  properties: {
    plan: { type: 'string' },
    tier: { type: 'string', enum: ['trivial', 'standard', 'high'] },
    touchedAreas: { type: 'array', items: { type: 'string' } },
    constitutionOk: { type: 'boolean' },
    constitutionViolations: { type: 'array', items: { type: 'string' } },
    planConcerns: { type: 'array', items: { type: 'string' } },
  },
};
const IMPL_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['worktreePath', 'branch', 'summary', 'filesChanged'],
  properties: { worktreePath: { type: 'string' }, branch: { type: 'string' }, summary: { type: 'string' }, filesChanged: { type: 'array', items: { type: 'string' } } },
};
const CHECK_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['checks', 'failingOutput'],
  properties: {
    checks: {
      type: 'array',
      items: {
        type: 'object', additionalProperties: false,
        required: ['name', 'command', 'result'],
        // `exit`/`tail` are ADDITIVE and optional — the attestation record needs the
        // raw exit code and a redacted output tail, but the verdict keys off `result`
        // only (verdictFrom is untouched). Optional so a cheap checks model that omits
        // them never fails schema-validation and collapses the whole gate to fail-closed.
        properties: { name: { type: 'string' }, command: { type: 'string' }, result: { type: 'string', enum: ['pass', 'fail'] }, exit: { type: 'number' }, tail: { type: 'string' } },
      },
    },
    failingOutput: { type: 'string' },
  },
};
const LENS_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['lens', 'findings', 'summary'],
  properties: { lens: { type: 'string' }, findings: { type: 'array', items: finding }, summary: { type: 'string' } },
};
const SHOT_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['captured', 'defects', 'verdict'],
  properties: {
    captured: { type: 'array', items: { type: 'string' } },
    defects: { type: 'array', items: { type: 'object', additionalProperties: false, required: ['breakpoint', 'defect', 'severity'], properties: { breakpoint: { type: 'string' }, defect: { type: 'string' }, severity: sev } } },
    verdict: { type: 'string', enum: ['pass', 'fail'] },
  },
};
const XMODEL_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['skipped', 'reason', 'findings'],
  properties: {
    skipped: { type: 'boolean' }, reason: { type: 'string' },
    findings: { type: 'array', items: { type: 'object', additionalProperties: false, required: ['severity', 'issue', 'fix'], properties: { severity: sev, issue: { type: 'string' }, fix: { type: 'string' } } } },
  },
};
const LAND_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['branch', 'commitSha', 'pushed', 'previewUrlOrNote', 'notes'],
  properties: { branch: { type: 'string' }, commitSha: { type: 'string' }, pushed: { type: 'boolean' }, previewUrlOrNote: { type: 'string' }, notes: { type: 'string' } },
};
// The run's own summary. Compression happens HERE, inside the loop, not in the
// owner's session: the raw result (plan + 4 lens reports + checks + probe +
// screenshot + land) is far too big to read, and shipping it out only to be
// summarized there wastes the owner's context on text they never see.
// LOSSLESS on anything decision-relevant; dedup is by ROOT CAUSE, not by lens.
const BRIEF_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['headline', 'changed', 'findings', 'landed', 'ownerActions'],
  properties: {
    headline: { type: 'string' },
    changed: { type: 'array', items: { type: 'string' } },
    findings: {
      type: 'array',
      items: {
        type: 'object', additionalProperties: false,
        required: ['severity', 'issue', 'location', 'raisedBy'],
        properties: {
          severity: { type: 'string', enum: ['BLOCKER', 'SHOULD-FIX', 'NIT', 'PRE-EXISTING'] },
          issue: { type: 'string' },
          location: { type: 'string' },
          raisedBy: { type: 'array', items: { type: 'string' } },
        },
      },
    },
    landed: { type: 'string' },
    ownerActions: { type: 'array', items: { type: 'string' } },
  },
};
// Re-runs a FAILED gate check against the base tree, so a check that was already
// RED before the change is not blamed on the change. `newFailures` is the guard:
// failure units present in the worktree run but NOT on base = a real regression
// added on top of a red baseline.
const BASE_PROBE_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['probes', 'cleanedUp'],
  properties: {
    probes: {
      type: 'array',
      items: {
        type: 'object', additionalProperties: false,
        required: ['name', 'baseResult', 'newFailures', 'evidence'],
        properties: {
          name: { type: 'string' },
          baseResult: { type: 'string', enum: ['pass', 'fail', 'error'] },
          newFailures: { type: 'array', items: { type: 'string' } },
          evidence: { type: 'string' },
        },
      },
    },
    cleanedUp: { type: 'boolean' },
  },
};

// ---------------- helpers ----------------
const wt = (p) =>
  `Work STRICTLY inside the isolated worktree at \`${p}\` (never the owner's main checkout, never a running dev server). Run every command with that directory as cwd.`;

// The owner's spec is BINDING: they already answered these questions, so an agent
// must not silently re-decide them.
const specBlock = spec
  ? `\n\nOWNER'S SPEC (from the /dev-loop interview — these decisions are already made; follow them, do not re-litigate or silently substitute your own):\n${spec}\n`
  : '';

function lensesForTier(tier) {
  return VERILOOP.experts.filter((e) => e.tiers.includes(tier)).map((e) => e.key);
}
function expertByKey(key) {
  return VERILOOP.experts.find((e) => e.key === key);
}

function tierRulesText() {
  const hi = VERILOOP.riskTiers.high.join(', ');
  const tr = VERILOOP.riskTiers.trivial.join(', ');
  return `Assign a risk TIER: 'high' if the change touches any danger surface (${hi}); 'trivial' if it is only ${tr}; otherwise 'standard'.`;
}

function lensPrompt(key, ctx) {
  const e = expertByKey(key);
  const base =
    `${RESOLVE}\n${wt(ctx.wt)}\n` +
    `Review this change on branch \`${ctx.branch}\` for the feature: "${feature}". The implementation is UNCOMMITTED in the worktree, so read it with \`git -C ${ctx.wt} diff ${ctx.baseBranch}\` (edits to tracked files) AND \`git -C ${ctx.wt} status --porcelain\` (any newly added files) — a plain \`${ctx.baseBranch}...${ctx.branch}\` diff is empty at this stage and is NOT the change. ` +
    `Ground every finding in the real code. Tag each BLOCKER / SHOULD-FIX / NIT. ` +
    `Also check the diff against every invariant in \`$REPO/${CONSTITUTION}\` — a violation is a BLOCKER.` +
    (spec ? ` Check it against the OWNER'S SPEC below too: contradicting an explicit design decision, or quietly dropping something the spec requires, is a BLOCKER (the code must do what the owner actually asked for, not a nearby thing).` : '') +
    ` Output findings only; change nothing.${specBlock}`;
  const persona =
    `Read \`$REPO/${e.file}\` AND, if it exists, \`$REPO/${e.overrides}\` (hand-authored overrides win on conflict), and adopt that reviewer persona (MODE: REVIEW).`;
  return `${persona}\n${base}`;
}

async function runLens(key, ctx, ph) {
  return agent(lensPrompt(key, ctx), { label: `lens:${key}`, phase: ph, schema: LENS_SCHEMA, ...route('review') });
}

async function runChecks(ctx, ph) {
  let list = VERILOOP.gate
    .map((c) => `- \`${c.cmd}\`  → report as check "${c.name}", result strictly from the process EXIT CODE (0=pass, nonzero=fail)`)
    .join('\n');
  // repo-specific extra gate checks (e.g. a DB security advisor) — from the interview
  for (const x of VERILOOP.extraChecks || []) {
    if (!x.areaKeywords.length || matchAny(ctx.touched, x.areaKeywords)) {
      list += `\n- ${x.instruction}  → report as check "${x.name}" (result pass/fail)`;
    }
  }
  const baselineNote = VERILOOP.gate.some((c) => c.verified === false)
    ? `\nNOTE: veriloop's smoke-run found ${VERILOOP.gate.filter((c) => c.verified === false).map((c) => c.name).join('/')} RED on the base tree — if it still fails identically, that is a pre-existing baseline issue, not this change; say so in failingOutput.`
    : '';
  return agent(
    `${RESOLVE}\n${wt(ctx.wt)}\n` +
      `Run the REAL gate checks for branch \`${ctx.branch}\` from the worktree and report each ONLY from its process exit code — never from your own reading of the output:\n${list}${baselineNote}\n` +
      `Return one entry per check with its name, the exact command, pass/fail, its integer process exit code (\`exit\`), and a short \`tail\` (the last ~20 lines of that check's output, length-capped). In \`tail\`, use repo-relative paths — strip the worktree/repo absolute prefix, and never include an absolute path or any \`.env*\` content. Put a short excerpt of any failure in failingOutput. Do NOT fix anything.`,
    { label: 'checks', phase: ph, schema: CHECK_SCHEMA, ...route('checks') },
  );
}

// Runs ONLY on the failure path: re-run the failed gate checks on a throwaway
// worktree detached at the base branch, to tell "this change broke it" from
// "it was already broken". A second worktree — never `git stash` in the feature
// worktree (a failed pop strands the change), never the owner's checkout.
async function runBaselineProbe(ctx, failed, failingOutput, ph) {
  const list = failed.map((c) => `- check "${c.name}": \`${c.command}\``).join('\n');
  const out = (failingOutput || '(none captured)').split('\n').slice(0, 60).map((l) => '    ' + l).join('\n');
  return agent(
    `${RESOLVE}\n` +
      `BASELINE PROBE. These gate checks FAILED on branch \`${ctx.branch}\`. Determine, for each, whether it ALSO fails on the untouched base branch \`${ctx.baseBranch}\` — i.e. whether the failure is pre-existing or was introduced by this change.\n\n${list}\n\n` +
      `Failure output captured from the FEATURE worktree run (excerpt):\n${out}\n` +
      `If that excerpt is not enough to enumerate the failure units, re-run the failed command in the feature worktree at \`${ctx.wt}\` to capture them (read-only; change nothing there).\n\n` +
      `Method:\n` +
      `1. Create a throwaway worktree detached at the base: \`git -C $REPO worktree add "$(dirname "${ctx.wt}")/.baseline-probe-${ctx.branch.replace(/[^A-Za-z0-9]+/g, '-')}" --detach ${ctx.baseBranch}\`. NEVER touch the owner's main checkout and NEVER stash or modify the feature worktree at \`${ctx.wt}\`.\n` +
      `2. Make dependencies available there the same way: ${VERILOOP.depsSetup}\n` +
      `3. Run ONLY the failed commands above in that probe worktree. Judge each strictly by its process EXIT CODE (0=pass, nonzero=fail) — never by reading the output.\n` +
      `4. For each check, compare FAILURE UNITS between the feature worktree's output (excerpts above) and the base run: the file paths a format check lists, the \`file:line\` locations a lint/typecheck reports, the failing test names a test run reports. \`newFailures\` = units failing in the FEATURE worktree that do NOT fail on base. Set baseResult='pass' if the check passes on base (so the change caused it), 'fail' if it fails on base too, 'error' if the command could not be run there at all.\n` +
      `5. FAIL SAFE: if you cannot confidently compare the two outputs unit-by-unit, say so in \`evidence\` and list the feature worktree's failure units in \`newFailures\` (treat them as new). Never guess a check clean.\n` +
      `6. ALWAYS remove the probe worktree when done, even if a command errored: \`git -C $REPO worktree remove --force <probe-dir>\`. Report cleanedUp=true only if it is actually gone.\n` +
      `Report findings only; fix NOTHING, and leave no branch or worktree behind.`,
    { label: 'baseline-probe', phase: ph, schema: BASE_PROBE_SCHEMA, ...route('checks') },
  );
}

async function runScreenshot(ctx, ph) {
  const e2e = VERILOOP.e2e ? `You may drive \`${VERILOOP.e2e.cmd}\` (on its own server/port) or the project's browser MCP.` : `Use the project's browser automation / Playwright MCP if present.`;
  return agent(
    `${RESOLVE}\n${wt(ctx.wt)}\n` +
      `VISUAL gate for the UI in branch \`${ctx.branch}\`. ${e2e} Capture the affected screens at 1440x900, 1280x620, and 760x470. ` +
      `**Navigate to the EXACT state this change affects — not the default view.** Drive the app all the way to the changed state before capturing; a screenshot of a screen where the changed control isn't active proves nothing, so treat "never reached the changed state" as verdict='fail'. ` +
      `Assert the changed control's real interactive state (clickable / not disabled), then OPEN every screenshot and list concrete visual defects (layout break, overflow, clipping, contrast, dead interaction). verdict='fail' if any real defect exists OR the live state wasn't exercised; else 'pass'. Verify — do not assume.`,
    { label: 'screenshot-gate', phase: ph, schema: SHOT_SCHEMA, ...route('review') },
  );
}

async function runXModel(ctx, ph) {
  return agent(
    `${RESOLVE}\n${wt(ctx.wt)}\n` +
      `CROSS-MODEL second opinion. First check whether the OpenAI Codex CLI is installed (\`command -v codex\`). If NOT installed, return {skipped:true, reason:"codex CLI not installed", findings:[]} — do not fail the gate. ` +
      `If installed, run it as an INDEPENDENT reviewer of the worktree change (\`git -C ${ctx.wt} diff ${ctx.baseBranch}\` plus \`git -C ${ctx.wt} status --porcelain\` for new files — the change is uncommitted, so a \`${ctx.baseBranch}...${ctx.branch}\` diff is empty) against the invariants in \`$REPO/${CONSTITUTION}\`, and return its blockers/concerns as findings (severity BLOCKER/SHOULD-FIX/NIT).`,
    { label: 'cross-model', phase: ph, schema: XMODEL_SCHEMA, ...route('review') },
  );
}

// <<< veriloop:verdict:start >>>
// Pure verdict logic (no closure over module state) — the selftest extracts this
// region and executes it directly against a table of cases.
function applyWaivers(blockers, waivers) {
  const ws = waivers || [];
  if (!ws.length) return { blockers, waived: [] };
  const kept = [], waived = [];
  for (const b of blockers) {
    if (ws.some((w) => b.toLowerCase().includes(w.toLowerCase()))) waived.push(b);
    else kept.push(b);
  }
  return { blockers: kept, waived };
}

function verdictFrom(checks, lenses, shot, xmodel, baseProbe, waivers, missingJobs) {
  let blockers = [], concerns = [];
  for (const k of (missingJobs || [])) {
    blockers.push(`gate job '${k}' did not return a result — a verification that does not run cannot pass (fail closed)`);
  }
  if (checks) {
    // A failed check is a BLOCKER unless the baseline probe proves it was ALREADY
    // failing on the base tree with no new failures added by this change. The
    // probe is the only authority for that downgrade: no probe, an errored probe,
    // or a probe that failed to clean up ⇒ blocker (fail safe — a red check is
    // never silently forgiven).
    const probeOk = !!(baseProbe && baseProbe.cleanedUp);
    for (const c of (checks.checks || [])) {
      if (c.result !== 'fail') continue;
      const label = `check: ${c.name} failed (\`${c.command}\`)`;
      const p = probeOk ? (baseProbe.probes || []).find((x) => x.name === c.name) : null;
      if (!p || p.baseResult !== 'fail') { blockers.push(label); continue; }
      const added = p.newFailures || [];
      if (added.length) blockers.push(`check: ${c.name} was already RED on the base tree, but this change ADDS new failures: ${added.join(', ')} (\`${c.command}\`)`);
      else concerns.push(`[pre-existing] check: ${c.name} was already RED on the base tree — not caused by this change (\`${c.command}\`)`);
    }
  }
  for (const l of (lenses || [])) for (const f of (l.findings || [])) {
    const tag = `[${l.lens}] ${f.issue}`;
    if (f.severity === 'BLOCKER') blockers.push(tag);
    else if (f.severity === 'SHOULD-FIX') concerns.push(tag);
  }
  if (shot && shot.verdict === 'fail') for (const d of (shot.defects || [])) blockers.push(`[ux/screenshot @${d.breakpoint}] ${d.defect}`);
  if (xmodel && !xmodel.skipped) for (const f of (xmodel.findings || [])) {
    const tag = `[cross-model] ${f.issue}`;
    if (f.severity === 'BLOCKER') blockers.push(tag); else concerns.push(tag);
  }
  const w = applyWaivers(blockers, waivers);
  blockers = w.blockers;
  let verdict;
  if (blockers.length) verdict = 'FAIL';
  else if (concerns.length) verdict = 'CONCERNS';
  else if (w.waived.length) verdict = 'WAIVED';
  else verdict = 'PASS';
  return { verdict, blockers, concerns, waived: w.waived };
}
// <<< veriloop:verdict:end >>>

// <<< veriloop:emit:start >>>
// PURE attestation-record builder — no Date, no fs, no process (all harness-forbidden,
// lint-bundle.mjs). The selftest extracts THIS region and executes it against a
// synthetic evidence object, so it must stay closure-free. It returns { relPath, json }:
// exactly ONE redacted `history/<ts>.json` record, a superset of the run's `evidence`
// fields. `ts/baseSha/headSha` arrive as `stamps` (placeholder tokens at runtime, real
// synthetic values in the test); the runtime emission step substitutes the tokens and
// writes the file (fs is forbidden here).
//
// REDACTION (constitution rule 7, BINDING — emitted artifacts are portable + secret-free):
// recursively over every string, (a) replace each known absolute root in `roots`
// (longest-first) with `$REPO`, then (b) DROP any remaining line that still matches the
// lint-bundle absolute-path regex. Imperfect root inference therefore degrades to a
// dropped line, never a leaked path. `.env*` content is never sourced into `evidence`.
function attestationFrom(evidence, ctx, stamps, roots) {
  const ABS = /(\/Users\/|\/home\/[a-z]|\b[A-Z]:[\\/])/; // === lint-bundle.mjs absolute-path regex
  const rootList = (roots || [])
    .filter((r) => typeof r === 'string' && r.length)
    .sort((a, b) => b.length - a.length); // longest-first: a worktree prefix before its parent
  const stripRoots = (s) => {
    let out = String(s);
    for (const r of rootList) out = out.split(r).join('$REPO');
    return out;
  };
  // strip known roots, then drop any line STILL carrying an absolute path (the safety net)
  const redactStr = (s) => stripRoots(s).split('\n').filter((line) => !ABS.test(line)).join('\n');
  const redact = (v) => {
    if (v == null || typeof v === 'number' || typeof v === 'boolean') return v;
    if (typeof v === 'string') return redactStr(v);
    if (Array.isArray(v)) {
      // redact each entry, then drop string entries that redaction emptied (a single-line
      // path that still matched the ABS regex collapses to '') so no bare path survives.
      return v.map(redact).filter((e) => !(typeof e === 'string' && e.length === 0));
    }
    const o = {};
    for (const k of Object.keys(v)) o[k] = redact(v[k]);
    return o;
  };
  // screenshot paths normalize to repo-relative first; the recursive net drops any that
  // could not be rooted (still absolute) rather than leaking them.
  const shot = evidence.screenshot || null;
  const normShot = (p) => stripRoots(p).replace(/^\$REPO[\\/]+/, '');
  const screenshots = shot && Array.isArray(shot.captured) ? shot.captured.map(normShot) : [];
  const land = evidence.land
    ? { sha: evidence.land.commitSha || null, pushed: !!evidence.land.pushed, branch: evidence.land.branch || (ctx && ctx.branch) || null }
    : null;
  const checks = (evidence.checks || []).map((c) => ({
    name: c.name,
    command: c.command,
    exit: (typeof c.exit === 'number') ? c.exit : (c.result === 'pass' ? 0 : 1),
    tail: c.tail || '',
  }));
  const record = {
    ts: stamps.ts,
    feature: evidence.feature,
    repo: evidence.repo,
    tier: evidence.tier,
    baseSha: stamps.baseSha,
    headSha: stamps.headSha,
    verdict: evidence.verdict,
    checks,
    baselineProbe: evidence.baselineProbe || null,
    screenshots,
    screenshotVerdict: shot ? shot.verdict : null,
    fixPasses: evidence.fixPasses,
    blockers: evidence.blockers || [],
    concerns: evidence.concerns || [],
    // free-text evidence rides along — all named redaction targets in the spec
    waived: evidence.waived || [],
    filesChanged: evidence.filesChanged || [],
    implSummary: evidence.implSummary || null,
    lenses: evidence.lenses || [],
    gateHistory: evidence.gateHistory || [],
    crossModel: evidence.crossModel || null,
    missingGateJobs: evidence.missingGateJobs || [],
    implPreflight: evidence.implPreflight || null,
    dryRun: !!evidence.dryRun,
    land,
  };
  const redacted = redact(record);
  return { relPath: `.claude/veriloop/history/${stamps.ts}.json`, json: JSON.stringify(redacted, null, 2) };
}
// <<< veriloop:emit:end >>>

function matchAny(areas, keywords) {
  return (areas || []).some((t) => keywords.some((k) => new RegExp(k, 'i').test(t)));
}

async function gate(ctx, ph) {
  const touchesUi = VERILOOP.hasUi && matchAny(ctx.touched, VERILOOP.uiAreas);
  const jobs = [{ key: 'checks', run: () => runChecks(ctx, ph) }];
  for (const key of lensesForTier(ctx.tier)) jobs.push({ key: `lens:${key}`, run: () => runLens(key, ctx, ph) });
  if (touchesUi) jobs.push({ key: 'shot', run: () => runScreenshot(ctx, ph) });
  if (ctx.tier === 'high' && VERILOOP.crossModel) jobs.push({ key: 'xmodel', run: () => runXModel(ctx, ph) });

  const out = await parallel(jobs.map((j) => j.run));
  const res = {};
  jobs.forEach((j, i) => { res[j.key] = out[i]; });
  // FAIL CLOSED: every job scheduled above was REQUIRED for this tier. A null
  // result means the agent died or was skipped — absent evidence, not passing
  // evidence. Each missing job becomes a blocker; only a human waiver may
  // downgrade it.
  const missingJobs = jobs.filter((j) => res[j.key] == null).map((j) => j.key);
  const checks = res.checks;
  const lenses = jobs.filter((j) => j.key.startsWith('lens:')).map((j) => res[j.key]).filter(Boolean);
  const shot = res.shot || null;
  const xmodel = res.xmodel || null;

  // Failure path only: a failed gate check is re-run against the base tree to
  // separate "this change broke it" from "it was already broken". Costs nothing
  // on the happy path, and runs AFTER the parallel jobs (never alongside the
  // lenses, which read the live worktree). extraChecks are interview-defined
  // instructions, not re-runnable commands — their failures stay blockers.
  const failedGate = ((checks && checks.checks) || []).filter(
    (c) => c.result === 'fail' && VERILOOP.gate.some((gc) => gc.name === c.name),
  );
  const baseProbe = failedGate.length
    ? await runBaselineProbe(ctx, failedGate, checks.failingOutput, ph)
    : null;

  const v = verdictFrom(checks, lenses, shot, xmodel, baseProbe, waivers, missingJobs);
  return { verdict: v.verdict, blockers: v.blockers, concerns: v.concerns, waived: v.waived, checks, lenses, screenshot: shot, xmodel, baseProbe, missingJobs };
}

const digest = (g) => ({ verdict: g.verdict, blockers: g.blockers.length, concerns: g.concerns.length, waived: g.waived.length });

// ---------------- 1. Plan (+ constitution + triage) ----------------
phase('Plan');
const planned = await agent(
  `${RESOLVE}\n` +
    `Read \`$REPO/${CONSTITUTION}\` and the baseline reviewer persona at \`$REPO/${VERILOOP.experts[0].file}\` (plus \`$REPO/${VERILOOP.experts[0].overrides}\` if it exists — hand-authored overrides win).\n` +
    `Design the smallest correct slice for this feature: "${feature}". Planning is just-in-time — depth scales with risk.${specBlock}\n` +
    (spec ? `The spec above is the owner's answer to the open design questions — build to it. If following it would break a constitution invariant, set constitutionOk=false and say so rather than quietly deviating.\n` : '') +
    `Then REVIEW your own plan and: (1) list the areas it will touch; (2) ${tierRulesText()} (3) check the plan against every invariant in the constitution and set constitutionOk=false with the specific violations if any invariant would be broken. Do NOT write code.`,
  { label: 'plan-review', phase: 'Plan', schema: PLAN_SCHEMA, ...route('plan') },
);
if (!planned.constitutionOk) {
  log(`HALT: plan violates the constitution (${planned.constitutionViolations.length} violation(s)).`);
  return { feature, halted: 'plan-violates-constitution', tier: planned.tier, violations: planned.constitutionViolations, plan: planned.plan };
}
log(`Plan OK — tier=${planned.tier}, touches: ${planned.touchedAreas.join(', ')}`);

// ---------------- 2. Implement (isolated worktree) ----------------
phase('Implement');
const staticChecks = VERILOOP.gate.filter((c) => c.name === 'typecheck' || c.name === 'lint');
const staticList = staticChecks.length ? staticChecks.map((c) => `\`${c.cmd}\``).join(' and ') : 'none configured — skip the pre-flight';
const impl = await agent(
  `${RESOLVE}\n` +
    `Implement this slice in an ISOLATED git worktree so the owner's main checkout is never touched.\n` +
    `Steps: pick a branch \`feat/<kebab-slug>\`; determine the base branch (\`git -C $REPO symbolic-ref --short HEAD\` or default main); create a persistent worktree OUTSIDE the repo (e.g. \`git -C $REPO worktree add "$(dirname "$REPO")/.${VERILOOP.repoName}-veriloop/<slug>" -b <branch> <base>\`).\n` +
    `MAKE DEPENDENCIES AVAILABLE so the gate's checks can run: ${VERILOOP.depsSetup}\n` +
    `Implement the plan below there (edits via the worktree path only); keep changes surgical and constitution-compliant. Do NOT commit, push, or review yet. ` +
    `Before returning, PRE-FLIGHT your work: run the gate's fast static checks once in the worktree — ${staticList} — judging strictly by exit code. If YOUR new code broke one, fix your code and re-run once. HARD LIMITS: never run a mutating command (no formatters/--write/--fix), never touch files outside your change to silence a check, and if a failure is not caused by your change, LEAVE IT and say so. Report what you finally saw in \`preflight\` (e.g. "typecheck exit 0, lint exit 0"). This report has ZERO authority — the gate re-runs everything itself and ignores your claim; its only purpose is to avoid burning a full gate cycle on a diff that does not compile.${specBlock}\n\nPLAN:\n${planned.plan}\n\nReturn the worktree path, the branch, the base branch used, a summary, and the files changed.`,
  { label: 'implement', phase: 'Implement', schema: { ...IMPL_SCHEMA, properties: { ...IMPL_SCHEMA.properties, baseBranch: { type: 'string' }, preflight: { type: 'string' } }, required: [...IMPL_SCHEMA.required, 'baseBranch'] }, ...route('implement') },
);
const ctx = { wt: impl.worktreePath, branch: impl.branch, baseBranch: impl.baseBranch || 'main', tier: planned.tier, touched: planned.touchedAreas };
log(`Implemented on ${ctx.branch} (${impl.filesChanged.length} files) in ${ctx.wt}`);

// ---------------- 3. Gate + 4. bounded Fix ----------------
phase('Gate');
let g = await gate(ctx, 'Gate');
const history = [digest(g)];
log(`Gate: ${g.verdict} (${g.blockers.length} blockers, ${g.concerns.length} concerns${g.waived.length ? ', ' + g.waived.length + ' waived' : ''})`);

let fixPass = 0;
if (g.verdict === 'FAIL') phase('Fix');
while (g.verdict === 'FAIL' && fixPass < MAX_FIX) {
  fixPass++;
  const prev = g.blockers.length;
  await agent(
    `${RESOLVE}\n${wt(ctx.wt)}\n` +
      `Fix pass ${fixPass}/${MAX_FIX} on branch \`${ctx.branch}\`. Resolve every BLOCKER (and cheap SHOULD-FIX). Make surgical, constitution-compliant changes; do not re-run the gate (the loop does).\n` +
      `A concern tagged \`[pre-existing]\` is a baseline issue that was ALREADY failing on \`${ctx.baseBranch}\` before this change — it is OUT OF SCOPE for this branch. Do NOT attempt to fix it and do not touch files outside this feature's scope to make it go green; the owner fixes the baseline separately.\n\nBLOCKERS:\n${g.blockers.map((b) => '- ' + b).join('\n')}\n\nCONCERNS (fix if cheap):\n${g.concerns.map((c) => '- ' + c).join('\n')}\n\nFAILING CHECK OUTPUT:\n${g.checks ? g.checks.failingOutput : ''}`,
    { label: `fix:pass${fixPass}`, phase: 'Fix', ...route('fix') },
  );
  g = await gate(ctx, 'Fix');
  history.push(digest(g));
  log(`After fix ${fixPass}: ${g.verdict} (${g.blockers.length} blockers)`);
  if (g.verdict === 'FAIL' && g.blockers.length >= prev) {
    log(`No progress (${prev} -> ${g.blockers.length} blockers) — escalating to owner.`);
    break;
  }
}

// ---------------- 5. Land (docs sync + push preview; NO merge/deploy) ----------------
phase('Land');
let land = null;
if (g.verdict === 'FAIL') {
  log('Final verdict FAIL after fix budget — NOT landing. Returning for owner triage.');
} else if (dryRun) {
  log(`DRY RUN — gate ${g.verdict}. Branch ${ctx.branch} left in the worktree ${ctx.wt}; NOT pushed, docs NOT synced. Review, then re-run without dryRun to land a preview.`);
} else {
  await agent(
    `${RESOLVE}\n${wt(ctx.wt)}\n` +
      `Docs sync for branch \`${ctx.branch}\`: update ONLY existing artifacts the change touched (README, docstrings/JSDoc, type defs, docs/plans, and \`$REPO/${CONSTITUTION}\` if a rule changed). Do not create new docs.`,
    { label: 'docs-sync', phase: 'Land', ...route('land') },
  );
  land = await agent(
    `${RESOLVE}\n${wt(ctx.wt)}\n` +
      `Land branch \`${ctx.branch}\` as a REVIEWABLE PREVIEW — do NOT merge to ${ctx.baseBranch}, do NOT deploy prod.\n` +
      `- Stage changes (NEVER \`.env*\`); commit with a conventional message using the repo's configured git author, NO AI co-author trailer.\n` +
      `- \`git push -u origin ${ctx.branch}\`.\n` +
      `- If a CI/preview integration exists it will build a preview — capture the URL if you can; otherwise note that the branch is pushed for review.\n` +
      `Return the commit sha, whether it pushed, and the preview URL or note.`,
    { label: 'land', phase: 'Land', schema: LAND_SCHEMA, ...route('land') },
  );
}

// ---------------- 6. Report (compress the run; no new judgments) ----------------
phase('Report');
const evidence = {
  feature,
  repo: VERILOOP.repoName,
  tier: ctx.tier,
  verdict: g.verdict,
  blockers: g.blockers,
  concerns: g.concerns,
  waived: g.waived,
  fixPasses: fixPass,
  gateHistory: history,
  filesChanged: impl.filesChanged,
  implSummary: impl.summary,
  checks: g.checks ? g.checks.checks : null,
  baselineProbe: g.baseProbe ? g.baseProbe.probes : null,
  lenses: (g.lenses || []).map((l) => ({ lens: l.lens, summary: l.summary, findings: l.findings })),
  screenshot: g.screenshot ? { verdict: g.screenshot.verdict, captured: g.screenshot.captured, defects: g.screenshot.defects } : null,
  crossModel: g.xmodel && !g.xmodel.skipped ? g.xmodel.findings : null,
  missingGateJobs: g.missingJobs || [],
  implPreflight: impl.preflight || null,
  land,
  dryRun,
};
const brief = await agent(
  `Compress this dev-loop run into the tightest brief that loses NOTHING the owner needs to decide with. You are summarizing, NOT reviewing: invent no findings, soften no severity, and drop no blocker or concern.\n\n` +
    `RULES:\n` +
    `- **Dedup by ROOT CAUSE, not by lens.** Several reviewers usually describe the SAME underlying defect in different words — state it ONCE, in the clearest wording, and list every lens that raised it in \`raisedBy\`. Convergence is signal: it belongs in the brief, not as repetition.\n` +
    `- Keep every distinct finding. If two findings share a root cause but need different fixes, they are two findings.\n` +
    `- A \`[pre-existing]\` concern gets severity 'PRE-EXISTING' and must say plainly it was already broken on \`${ctx.baseBranch}\` and is not this change's fault.\n` +
    `- \`changed\`: one line per file — the file and what changed in it, concretely.\n` +
    `- \`location\`: a real \`file:line\` or \`file\` from the findings; never invent one.\n` +
    `- \`ownerActions\`: ONLY what the human must actually decide or do (review the pushed branch, merge, fix a baseline, resolve a blocker). If nothing is needed, return an empty array. Never pad.\n` +
    `- \`headline\`: ONE sentence — the verdict and what actually happened. Plain words, no hedging, no restating the feature request.\n` +
    `- Write plain prose. No filler, no "successfully", no restating these instructions.\n\n` +
    `RUN EVIDENCE (JSON):\n${JSON.stringify(evidence, null, 1)}`,
  { label: 'report', phase: 'Report', schema: BRIEF_SCHEMA, ...route('report') },
);

// ---------------- 6b. Emit attestation record (redacted; committed only if landed) ----
// The evidence spine's durable track record: one redacted `history/<ts>.json` per run.
// dryRun's contract is no persistence side effects, so it emits nothing. The redaction
// (constitution rule 7) runs HERE in pure JS; the agent below only fills the three
// runtime tokens (ts/base/head shas) and writes the bytes — fs/Date/git are forbidden
// in this workflow context, so the write is delegated to a worktree agent.
if (!dryRun) {
  // roots the redactor strips to `$REPO`: the worktree, and the repo root derived from
  // the standard `<parent>/.<repo>-veriloop/<slug>` worktree layout. Any absolute path
  // these miss is caught by the drop-net (a line still matching the ABS regex is removed).
  const marker = `/.${VERILOOP.repoName}-veriloop/`;
  const mi = ctx.wt.indexOf(marker);
  const repoRootGuess = mi >= 0 ? `${ctx.wt.slice(0, mi)}/${VERILOOP.repoName}` : null;
  const roots = [ctx.wt, repoRootGuess].filter(Boolean);
  const att = attestationFrom(
    evidence,
    ctx,
    { ts: '__VERILOOP_TS__', baseSha: '__VERILOOP_BASE_SHA__', headSha: '__VERILOOP_HEAD_SHA__' },
    roots,
  );
  const landedNow = !!(land && land.pushed);
  await agent(
    `${RESOLVE}\n${wt(ctx.wt)}\n` +
      `Write this run's ATTESTATION RECORD. The JSON is ALREADY REDACTED and final — do NOT edit, reformat, re-key, or add fields; only substitute the three runtime tokens and write the exact bytes.\n` +
      `Steps (run in the worktree):\n` +
      `1. Compute: \`ts=$(date -u +%Y-%m-%dT%H-%M-%SZ)\`; \`headSha=$(git rev-parse HEAD)\`; \`baseSha=$(git rev-parse ${ctx.baseBranch})\`.\n` +
      `2. In the JSON below, replace every \`__VERILOOP_TS__\` with $ts, \`__VERILOOP_HEAD_SHA__\` with $headSha, \`__VERILOOP_BASE_SHA__\` with $baseSha. Change NOTHING else.\n` +
      `3. \`mkdir -p $REPO/.claude/veriloop/history\` and write the result to \`$REPO/.claude/veriloop/history/$ts.json\` (exactly one file). Verify it parses as JSON.\n` +
      (landedNow
        ? `4. This run LANDED — commit the record on branch \`${ctx.branch}\` with a conventional message (e.g. \`chore(veriloop): attestation record for ${ctx.branch}\`), NO AI co-author trailer, then \`git push\`. Leave \`git status\` clean.\n`
        : `4. This run did NOT land — do NOT commit or push. Leave the record in the worktree for owner triage.\n`) +
      `HARD LIMITS: never stage or echo \`.env*\`; never add an absolute path back into the record; the record is runtime output — do NOT add it to the manifest's emitted_files.\n\n` +
      `RECORD JSON (write verbatim, tokens substituted):\n${att.json}`,
    { label: 'emit-attestation', phase: 'Report', ...route('land') },
  );
}

const GROUPS = ['plan', 'implement', 'review', 'checks', 'fix', 'land', 'report'];
return {
  brief,
  feature,
  repo: VERILOOP.repoName,
  tier: ctx.tier,
  touched: ctx.touched,
  spec: spec || null,
  posture: argsObj.posture || (VERILOOP.budget && VERILOOP.budget.posture) || 'balanced',
  routing: Object.fromEntries(GROUPS.map((g) => {
    const r = route(g);
    return [g, `${r.model || 'session default'}${r.effort ? ' / ' + r.effort : ''}`];
  })),
  plan: planned.plan,
  finalVerdict: g.verdict,
  blockers: g.blockers,
  concerns: g.concerns,
  waived: g.waived,
  fixPasses: fixPass,
  gateHistory: history,
  branch: ctx.branch,
  worktree: ctx.wt,
  dryRun,
  land,
  ownerGate: dryRun
    ? 'DRY RUN — nothing pushed. Review the diff + gate in the worktree; re-run without dryRun to land a preview.'
    : 'Loop stopped before merge/deploy. Review the preview and give explicit sign-off to merge/deploy.',
};
